PARAMS = {'items': 2, 'periods': 5, 'initial_inventory': [15, 15], 'demand': [[45, 36, 15, 24, 17], [39, 17, 19, 41, 28]], 'volume': [3, 4], 'storage_capacity': 111, 'unit_order_cost': [4, 5], 'holding_cost': [2, 4]}


def build_model():
    from replenishverifier.benchmark.templates import build_model as _build_model
    return _build_model(PROBLEM_TYPE, PARAMS)


if __name__ == "__main__":
    model = build_model()
    model.solve(pulp.PULP_CBC_CMD(msg=False))
    print(pulp.LpStatus[model.status])
    print(pulp.value(model.objective))

